INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0305220N$$, 2027, $$The MQ-4C Triton Unmanned Air System (UAS) is a high altitude-long endurance UAS designed to provide Fleet and combatant commanders with persistent maritime
Intelligence, Surveillance Reconnaissance and Targeting (ISR&T) of nearly all the world's high-density sea-lanes, littorals, and areas of national interest. The Triton
air vehicle, mission control system, specialized sensors, and communications suite play a significant role in achieving the Navy's strategic vision for the 21st century.
Triton provides persistent ISR&T and unparalleled situational awareness of the maritime battle space to the supported combatant commander and fleet commander.
Triton provides the Warfighter with unprecedented levels of battlespace awareness to synchronize actions necessary to maintain maritime full spectrum superiority.
Teamed with its manned-capability counterpart, the P-8A Poseidon, Triton is a key component of the Navy's maritime domain awareness family of systems. MQ-4C
Triton leverages Maritime Patrol and Reconnaissance Force manpower, training and maintenance efficiencies.

Triton Early Operational Capability (EOC) was successfully deployed in 2020 to provide early fleet integration risk reduction. It successfully prepared the fleet for fielding
Initial Operational Capability (IOC) and concluded in 2022. In August of 2023 Triton fielded the Increment 1 Multi-Intelligence (Multi-INT) IOC on schedule, successfully
meeting the 2011 National Defense Authorization (NDAA) requirements. This enabled the Navy's Maritime Intelligence, Surveillance, Reconnaissance, and Targeting
(MISR-T) transition plan and initiated EP-3 Aries sundown. The Increment 1 Multi-INT capability provides Signals Intelligence (SIGINT), Counter Electronic Attack (CEA)
upgrades, and data dissemination across multiple classification domains.

Project Unit 4020: MQ-4C Triton Baseline funding supported developmental efforts from the inception of the program and continues to fund air vehicle Full Scale Fatigue
Testing (FSFT), Effects of Defects (EoD) test efforts and updates to fatigue and damage tolerance analyses to fully verify and validate fatigue and damage tolerance
requirements of the MQ-4C Triton Performance Based System Specification (PBSS). Fatigue testing results are required to certify the airframe to its current designed
service life of 51,000 flight hours/2,029 landings. The duration of fatigue testing is paced by the cycling rate limit of the test fixture/equipment for the main wing/fuselage/
tail test article, as well as time to perform teardown activities and inspect for cracks. Baseline funding also includes developmental efforts that improve the air vehicle
reliability, availability, maintainability, and performance.$$, $$The MQ-4C Triton Unmanned Air System (UAS) is a high altitude-long endurance UAS designed to provide Fleet and combatant commanders with persistent maritime
Intelligence, Surveillance Reconnaissance and Targeting (ISR&T) of nearly all the world's high-density sea-lanes, littorals, and areas of national interest. The Triton
air vehicle, mission control system, specialized sensors, and communications suite play a significant role in achieving the Navy's strategic vision for the 21st century.
Triton provides persistent ISR&T and unparalleled situational awareness of the maritime battle space to the supported combatant commander and fleet commander.
Triton provides the Warfighter with unprecedented levels of battlespace awareness to synchronize actions necessary to maintain maritime full spectrum superiority.
Teamed with its manned-capability counterpart, the P-8A Poseidon, Triton is a key component of the Navy's maritime domain awareness family of systems. MQ-4C
Triton leverages Maritime Patrol and Reconnaissance Force manpower, training and maintenance efficiencies.

Triton Early Operational Capability (EOC) was successfully deployed in 2020 to provide early fleet integration risk reduction. It successfully prepared the fleet for fielding
Initial Operational Capability (IOC) and concluded in 2022. In August of 2023 Triton fielded the Increment 1 Multi-Intelligence (Multi-INT) IOC on schedule, successfully
meeting the 2011 National Defense Authorization (NDAA) requirements. This enabled the Navy's Maritime Intelligence, Surveillance, Reconnaissance, and Targeting
(MISR-T) transition plan and initiated EP-3 Aries sundown. The Increment 1 Multi-INT capability provides Signals Intelligence (SIGINT), Counter Electronic Attack (CEA)
upgrades, and data dissemination across multiple classification domains.

Project Unit 4020: MQ-4C Triton Baseline funding supported developmental efforts from the inception of the program and continues to fund air vehicle Full Scale Fatigue
Testing (FSFT), Effects of Defects (EoD) test efforts and updates to fatigue and damage tolerance analyses to fully verify and validate fatigue and damage tolerance
requirements of the MQ-4C Triton Performance Based System Specification (PBSS). Fatigue testing results are required to certify the airframe to its current designed
service life of 51,000 flight hours/2,029 landings. The duration of fatigue testing is paced by the cycling rate limit of the test fixture/equipment for the main wing/fuselage/
tail test article, as well as time to perform teardown activities and inspect for cracks. Baseline funding also includes developmental efforts that improve the air vehicle
reliability, availability, maintainability, and performance.

